/**
 * Embedding-based NotebookLM router.
 * Uses @xenova/transformers (ONNX) to run a local multilingual embedding model.
 * On startup, generates centroid vectors for each notebook from its `repr` text.
 * Per user turn, embeds the message and returns notebooks above a similarity threshold.
 */

import { pipeline } from "@xenova/transformers";

// ─── Types ───────────────────────────────────────────────────────────────────

export interface RoutingV2Notebook {
  notebook_id: string;
  title: string;
  repr: string;
  strategy: "primary" | "parallel_compare" | "parallel_merge";
}

export interface RoutingV2MultiMatchRule {
  notebooks: string[]; // titles
  strategy: "parallel_compare" | "parallel_merge";
  note?: string;
}

export interface RoutingV2 {
  version: 2;
  generated_at: string;
  threshold: number;
  notebooks: RoutingV2Notebook[];
  multi_match_rules: RoutingV2MultiMatchRule[];
}

export interface RouteHit {
  notebookId: string;
  title: string;
  strategy: "primary" | "parallel_compare" | "parallel_merge";
  score: number;
}

// ─── State ───────────────────────────────────────────────────────────────────

const MODEL_NAME = process.env.EMBED_MODEL || "Xenova/bge-small-zh-v1.5";
const DEFAULT_ROUTING_THRESHOLD = 0.65;

let embedder: any = null;
let centroids: Map<string, Float32Array> = new Map(); // notebook_id → vector
let routingTable: RoutingV2 | null = null;

// ─── Public API ──────────────────────────────────────────────────────────────

export async function initEmbedRouter(routing: RoutingV2): Promise<void> {
  routingTable = routing;
  embedder = await pipeline("feature-extraction", MODEL_NAME);
  centroids.clear();
  for (const nb of routing.notebooks) {
    const vec = await embed(nb.repr);
    centroids.set(nb.notebook_id, vec);
  }
  console.log(
    `[embed-router] ready: model=${MODEL_NAME}, ${centroids.size} centroids`,
  );
}

export function isEmbedRouterReady(): boolean {
  return embedder !== null && centroids.size > 0;
}

/**
 * Route a user message to matching notebooks.
 * Returns hits sorted by descending score, applying multi_match_rules when applicable.
 */
export async function routeByEmbedding(
  userMsg: string,
  /** If provided, only consider notebooks whose title is in this set. */
  titleFilter?: Set<string>,
  /** Override threshold (e.g. lower when scope already narrows candidates). */
  thresholdOverride?: number,
): Promise<RouteHit[]> {
  if (!embedder || !routingTable) return [];
  if (userMsg.trim().length < 8) return [];
  const queryVec = await embed(userMsg);
  const threshold =
    thresholdOverride ?? routingTable.threshold ?? DEFAULT_ROUTING_THRESHOLD;

  // Score all notebooks
  const scored: RouteHit[] = [];
  for (const nb of routingTable.notebooks) {
    if (titleFilter && !titleFilter.has(nb.title)) continue;
    const centroid = centroids.get(nb.notebook_id);
    if (!centroid) continue;
    const score = cosineSim(queryVec, centroid);
    if (score >= threshold) {
      scored.push({
        notebookId: nb.notebook_id,
        title: nb.title,
        strategy: nb.strategy,
        score,
      });
    }
  }
  if (scored.length === 0) return [];
  scored.sort((a, b) => b.score - a.score);

  // Keep at most top 2 hits to avoid over-querying
  const topHits = scored.slice(0, 2);

  // Check multi_match_rules: if 2+ hits match a rule's notebook set, override strategy
  if (topHits.length >= 2 && routingTable.multi_match_rules.length > 0) {
    const hitTitles = new Set(topHits.map((h) => h.title));
    for (const rule of routingTable.multi_match_rules) {
      if (rule.notebooks.every((t) => hitTitles.has(t))) {
        // Apply rule strategy to matched notebooks
        for (const hit of topHits) {
          if (rule.notebooks.includes(hit.title)) {
            hit.strategy = rule.strategy;
          }
        }
        break; // first matching rule wins
      }
    }
  }

  return topHits;
}

// ─── Shared utilities (used by memory-recall, skill-router, etc.) ────────────

/**
 * Embed arbitrary text using the loaded model. Returns null if model not ready.
 * Reusable by other modules that need embedding vectors.
 */
export async function embedText(text: string): Promise<Float32Array | null> {
  if (!embedder) return null;
  return embed(text);
}

export function cosineSim(a: Float32Array, b: Float32Array): number {
  let dot = 0;
  for (let i = 0; i < a.length; i++) dot += a[i] * b[i];
  return dot; // already L2-normalized → dot = cosine
}

// ─── Internals ───────────────────────────────────────────────────────────────

async function embed(text: string): Promise<Float32Array> {
  // Strip chat-template special tokens that some models leak into output.
  // The BGE tokenizer rejects them, causing "Disallowed special token" errors.
  const clean = text.replace(/<\|[a-z_]+\|>/g, "");
  const output = await embedder!(clean, { pooling: "mean", normalize: true });
  return output.data as Float32Array;
}

