const RESTART_PENDING_FILE = path.join(MEMORY_DIR, ".restart-pending.json");
const PENDING_EXTRACT_FILE = path.join(MEMORY_DIR, "pending-extract.jsonl");

// ---------------------------------------------------------------------------
