const SCHEDULE_FILE = path.join(MEMORY_DIR, "schedules.json");
const scheduleStore = new ScheduleStore(SCHEDULE_FILE);
const scheduler = new Scheduler(bot, scheduleStore);

// When /restart flushes sessions, onBeforeClose uses this to know which chat
// should have its save result recorded into the pending marker. Set by
