bot.on("message:text", async (ctx) => {
  if (!isAllowed(ctx)) {
    await ctx.reply("Not authorized.");
    return;
  }
  const text = ctx.message.text;
  const chatId = ctx.chat.id;

  // ── /cancel all: silently drop messages that were queued before the cancel ──
  if (!text.startsWith("/") && sessions.shouldDrop(chatId, ctx.message.date)) {
    return; // silently discard
  }

  // ── 群組模式：只有被 @mention 才回應，防止兩個 bot 同時反應 ──
  if (ctx.chat.type !== "private") {
    const botUsername = ctx.me.username;
    // Use word-boundary regex so @RK_AI_bot doesn't also match @RK_AI_bot2
    const mentionRe = new RegExp(`@${botUsername}(?![a-zA-Z0-9_])`, "i");
    if (!mentionRe.test(text)) return;

    // Group relevance filter: skip if message (after removing @mention) is
    // too short or clearly irrelevant to bot capabilities.
    const stripped = text.replace(mentionRe, "").trim();
    if (stripped.length < 1) return; // e.g. just "@bot" with nothing else

    // 防止 bot 互相無限乒乓：如果訊息包含 <<DONE>> 標記就不回應
    if (text.includes("<<DONE>>")) return;

    // 來自其他 bot 的訊息：檢查連續回覆次數防止迴圈
    if (ctx.from?.is_bot) {
      const key = `group_turns_${chatId}`;
      const turns = (groupTurnCounters.get(key) ?? 0) + 1;
      groupTurnCounters.set(key, turns);
      if (turns > GROUP_MAX_BOT_TURNS) {
        groupTurnCounters.set(key, 0);
        await ctx.reply("⚠️ 已達群組 bot 連續回覆上限，暫停回應。");
        return;
      }
    } else {
      // 人類發話時重置計數器
      const key = `group_turns_${chatId}`;
      groupTurnCounters.set(key, 0);
      getRelayLoopGuard()?.reset();
    }
  }

  // AB-7b: a real user message always preempts a pending goal
  // continuation. Cancel the timer before anything else so we don't
  // race with it. If the message is itself the start of a /goal
  // command, handleGoal will later take care of setting up the new
  // state; otherwise the goal loop just sits idle until agent emits
  // GOAL_DONE or the user issues /goal pause/clear.
  cancelPendingContinuation(chatId);

  // Any human message resets the relay idle-loop counter.
  getRelayLoopGuard()?.reset();

  // ── /schedule wizard: consume the next plain-text reply as <prompt> ──
  // Only applies when a pending entry exists and the message is NOT a slash
  // command (so /cancel or another /schedule still work to abort). Expired
  // entries are swept and ignored.
  const pending = pendingSchedules.get(chatId);
  if (pending && !text.startsWith("/")) {
    if (Date.now() - pending.createdAt > PENDING_SCHEDULE_TTL_MS) {
      pendingSchedules.delete(chatId);
      await ctx.reply("排程精靈已逾時（5 分鐘未輸入 prompt），請重新 /schedule。");
      return;
    }
    const prompt = text.trim();
    if (!prompt) {
      await ctx.reply("prompt 不可為空。請輸入要觸發時送給 agent 的文字。");
      return;
    }
    pendingSchedules.delete(chatId);
    // Dispatch through handleSchedule by synthesising ctx.match. This keeps
    // one source of truth for parseDuration / parseRecurrence / scheduleStore.
    const synthetic = `${pending.kind} ${pending.time} ${prompt}`;
    (ctx as Context & { match?: string }).match = synthetic;
    await handleSchedule(ctx);
    return;
  }
  if (pending && text.startsWith("/")) {
    // Slash command while pending — assume user wants to do something else.
    pendingSchedules.delete(chatId);
  }

  if (text.startsWith("/")) {
    // In proxy mode, /back must still work even if bot.command() didn't fire.
    if (/^\/back(?:@\w+)?(?:\s|$)/i.test(text) && isProxyActive(chatId)) {
      const proxySession = endProxy(chatId);
      if (proxySession) {
        await ctx.reply(`✅ 已退出 specialist "${proxySession.specialistName}" proxy 模式。`);
        const summary = buildProxySummary(proxySession);
        const userId = ctx.from?.id ?? chatId;
        const session = await sessions.get(chatId, userId);
        runPrompt(ctx, session, summary, { kind: "meta" }).catch((err) =>
          console.error(`[chat ${chatId}] proxy summary injection failed:`, err),
        );
      }
      return;
    }
    // Dispatch through COMMAND_HANDLERS for commands without explicit bot.command()
    const cmdMatch = text.match(/^\/(\w+)(?:@\w+)?\s*(.*)/);
    if (cmdMatch) {
      const cmdName = cmdMatch[1].toLowerCase();
      const handler = COMMAND_HANDLERS[cmdName];
      if (handler) {
        (ctx as Context & { match?: string }).match = cmdMatch[2] || "";
        await handler(ctx);
        return;
      }
    }
    return; // unknown command, ignore
  }

  let session: ChatSession;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`
    );
    return;
  }

  // ── Specialist proxy mode: bypass main agent, send directly to specialist ──
  if (isProxyActive(chatId)) {
    const target = getProxyTarget(chatId)!;
    try {
      // Send placeholder for streaming edits
      const prefix = `🤖 *[${target}]*\n`;
      const placeholder = await ctx.reply(`${prefix}Thinking… ▍`, { parse_mode: "Markdown" })
        .catch(() => ctx.reply(`🤖 [${target}]\nThinking… ▍`));

      let lastEditAt = 0;
      let lastRendered = "";
      let editTimer: NodeJS.Timeout | null = null;

      const editNow = async (content: string) => {
        if (rateLimitedUntil() > Date.now()) return;
        const body = content.length > TG_MAX
          ? "…" + content.slice(-TG_MAX)
          : content;
        const frame = `${prefix}${body} ▍`;
        if (frame === lastRendered) return;
        lastRendered = frame;
        lastEditAt = Date.now();
        try {
          await ctx.api.editMessageText(chatId, placeholder.message_id, frame, { parse_mode: "Markdown" });
        } catch {
          // 400 if content identical or markdown parse error — ignore
          await ctx.api.editMessageText(chatId, placeholder.message_id, `🤖 [${target}]\n${body} ▍`).catch(() => {});
        }
      };

      const onChunk = (currentOutput: string) => {
        const stripped = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, "").trim();
        if (!stripped) return;
        const elapsed = Date.now() - lastEditAt;
        if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
          editNow(stripped);
        } else if (!editTimer) {
          editTimer = setTimeout(() => {
            editTimer = null;
            const latest = stripMemoryTokens(currentOutput).replace(/<<PROXY_DONE>>/gi, "").trim();
            if (latest) editNow(latest);
          }, STREAM_EDIT_INTERVAL_MS - elapsed);
        }
      };

      const { output, proxyDone } = await promptProxy(chatId, text, onChunk, ctx.from?.id);
      if (editTimer) { clearTimeout(editTimer); editTimer = null; }

      // Extract memory tokens from specialist output and write to main agent's facts.
      extractMemoryTokensFromProxy(output, ctx.from?.id ?? chatId);

      // Run observer transformer on proxy output — handles SEND_FILE, ASK, STICKER
      const proxyTokens = transformReplyTokens(output, {
        parseDuration,
        parseAbsoluteTime,
        parseRecurrence,
        computeNextRunAt,
      });

      // Send files
      if (proxyTokens.sendFiles.length > 0) {
        sendFilesByPaths(ctx, proxyTokens.sendFiles).catch((err) =>
          console.error(`[specialist:proxy] sendFilesByPaths failed:`, err));
      }

      // Send stickers
      for (const emotion of proxyTokens.stickerEmotions) {
        const fileId = STICKER_MAP[emotion];
        if (fileId) {
          ctx.replyWithSticker(fileId).catch((err) =>
            console.warn(`[specialist:proxy] STICKER ${emotion} failed:`, (err as Error).message));
        }
      }

      // SKILL_USED
      if (proxyTokens.skillUsages.length > 0) {
        const skillDir = detectSkillDir();
        if (!skillDir.startsWith("(")) {
          for (const u of proxyTokens.skillUsages) {
            usageStore.markUsed(skillDir, u.name, u.reason).catch(() => {});
          }
        }
      }

      // Final edit: use token-stripped text as display
      const display = proxyTokens.text.trim();
      // Append ctx usage line for proxy (mirrors main agent's footer)
      const proxyStats = getProxyStats(chatId);
      const proxyUsage = (() => {
        if (!proxyStats) return "";
        const inTok = estimateTokens(proxyStats.charsIn);
        const outTok = estimateTokens(proxyStats.charsOut);
        const totalTok = inTok + outTok;
        const limit = config.contextWindowTokens;
        const pctStr = limit ? ((totalTok / limit) * 100).toFixed(1) + "%" : "";
        return `\n\n— ctx ~${totalTok}/${limit} tok (${pctStr}) • in ${inTok} · out ${outTok}`;
      })();
      if (display) {
        const fullText = `${display}${proxyUsage}`;
        const chunks = splitForTelegram(fullText);
        // ASK keyboard (if specialist emitted <<ASK:...>> tokens)
        const proxyAskKb = buildAskKeyboard(proxyTokens.askTokens);
        // First chunk: edit the placeholder
        const first = `${prefix}${chunks[0]}`;
        const isLastChunk = chunks.length === 1;
        await ctx.api.editMessageText(chatId, placeholder.message_id, first, {
          parse_mode: "Markdown",
          ...(isLastChunk && proxyAskKb ? { reply_markup: proxyAskKb } : {}),
        }).catch(() => ctx.api.editMessageText(chatId, placeholder.message_id, `🤖 [${target}]\n${chunks[0]}`, {
          ...(isLastChunk && proxyAskKb ? { reply_markup: proxyAskKb } : {}),
        }).catch(() => {}));
        if (isLastChunk && proxyAskKb) {
          askRegistry.set(placeholder.message_id, proxyTokens.askTokens);
        }
        // Remaining chunks: send as new messages
        for (let ci = 1; ci < chunks.length; ci++) {
          const isLast = ci === chunks.length - 1;
          const msg = await ctx.api.sendMessage(chatId, chunks[ci], {
            parse_mode: "Markdown",
            ...(isLast && proxyAskKb ? { reply_markup: proxyAskKb } : {}),
          }).catch(() => ctx.api.sendMessage(chatId, chunks[ci]).catch(() => null));
          if (isLast && proxyAskKb && msg?.message_id) {
            askRegistry.set(msg.message_id, proxyTokens.askTokens);
          }
        }
      } else {
        await ctx.api.editMessageText(chatId, placeholder.message_id, `${prefix}(no response)`, { parse_mode: "Markdown" }).catch(() => {});
      }
      // Auto-exit if specialist signaled done.
      if (proxyDone) {
        const proxySession = endProxy(chatId);
        await ctx.reply(`✅ Specialist "${target}" 完成，已切回主 agent。`);
        if (proxySession) {
          const summary = buildProxySummary(proxySession);
          const userId = ctx.from?.id ?? chatId;
          const session = await sessions.get(chatId, userId);
          const fakeCtx = {
            chat: { id: chatId, type: "private" as const },
            from: { id: userId, is_bot: false, first_name: "system" },
            message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: summary },
            api: bot.api,
            reply: (t: string, extra?: any) => bot.api.sendMessage(chatId, t, extra),
          } as unknown as Context;
          runPrompt(fakeCtx, session, summary, { kind: "meta" }).catch(() => {});
        }
      }
    } catch (err) {
      console.error(`[specialist:proxy] prompt to "${target}" failed:`, err);
      await ctx.reply(`⚠️ Specialist "${target}" 回覆失敗：${(err as Error).message}`);
    }
    return;
  }

  // ── Specialist pre-filter: hint the main agent to route if local LLM is confident ──
  const _enrichStart = Date.now();
  let specialistHint = "";
  if (config.localLlmPrefilter && session.activeProvider !== "local") {
    const t0 = Date.now();
    try {
      const specialists = getSpecialists();
      if (specialists.length > 0) {
        const descs = specialists.map(s => ({
          name: s.name,
          description: s.name === "slot-dev" ? "UK slot game development with Cocos 3.6.2"
            : s.name === "video-prod" ? "Video production, TTS, ffmpeg, sticker pipeline"
            : s.name === "researcher" ? "Deep research on any topic (tech, business, science)"
            : s.name,
        }));
        const route = await prefilterSpecialistRoute(text, descs);
        // Routing Coordinator: augment keyword result with LLM semantic classification
        const coordResult = await shouldRoute(text, route.target);
        const finalTarget = coordResult.target;
        const routeMethod = coordResult.method;
        if (finalTarget) {
          console.log(`[pre-filter] suggesting specialist: ${finalTarget} via ${routeMethod} (${Date.now() - t0}ms)`);
          specialistHint =
            `[Specialist routing hint — pre-filter suggests this message belongs to "${finalTarget}" specialist (method=${routeMethod}). ` +
            `Consider using <<SPECIALIST_PROXY:${finalTarget}|${text.slice(0, 100)}>> if appropriate.]\n\n`;
          appendRoutingLog({ message: text.slice(0, 200), routedTo: finalTarget, method: routeMethod as any, confidence: route.confidence });
        } else {
          console.log(`[pre-filter] no match (${Date.now() - t0}ms)`);
          appendRoutingLog({ message: text.slice(0, 200), routedTo: "self", method: routeMethod as any, confidence: route.confidence });
        }
      }
    } catch { /* pre-filter failed — continue without hint */ }
  }

  // Embedding-based NotebookLM routing: if the user message is semantically
  // close to a notebook's repr, prepend a context hint so the agent queries it.
  let promptText = text;
  const _skipEnrichment = session.activeProvider === "local";
  if (!_skipEnrichment && isEmbedRouterReady()) {
    try {
      const hits = await routeByEmbedding(text);
      if (hits.length > 0) {
        const hitLines = hits.map(
          (h) => `- 《${h.title}》(id=${h.notebookId}, score=${h.score.toFixed(3)}, strategy=${h.strategy})`,
        );
        promptText =
          `[NotebookLM routing — embedding match]\n` +
          `以下 notebook 與使用者問題語意相近，請用 notebook_query 查詢後以該 strategy 格式回答：\n` +
          hitLines.join("\n") +
          `\n[End routing]\n\n${text}`;
      }
    } catch (err) {
      console.warn("[embed-router] route failed:", err);
    }
  }

  // Wiki retrieval: auto-inject relevant wiki page content.
  // Runs before memory-recall so we can skip topics already covered by wiki.
  const wikiHitSlugs = new Set<string>();
  if (!_skipEnrichment && isWikiRetrievalReady()) {
    try {
      const hits = await retrieveWikiPages(text);
      // Per-session dedup: skip pages already injected in a prior turn.
      const fresh = hits.filter((h) => !session.injectedWikiSlugs.has(h.slug));
      if (fresh.length > 0) {
        for (const h of fresh) {
          wikiHitSlugs.add(h.slug);
          session.injectedWikiSlugs.add(h.slug);
        }
        promptText = formatWikiBlock(fresh) + promptText;
      }
    } catch (err) {
      console.warn("[wiki-retrieval] failed:", err);
    }
  }

  // Memory recall: inject semantically relevant topic shard facts.
  if (!_skipEnrichment && isMemoryRecallReady() && ctx.from?.id) {
    try {
      const hits = await recallRelevantFacts(
        text, ctx.from.id, session.tailFacts, wikiHitSlugs,
      );
      if (hits.length > 0) {
        promptText = formatRecallBlock(hits) + promptText;
      }
    } catch (err) {
      console.warn("[memory-recall] failed:", err);
    }
  }

  // Skill routing: hint which skills are most relevant.
  if (!_skipEnrichment && isSkillRouterReady()) {
    try {
      const hits = await routeToSkills(text);
      // Per-session dedup: skip skills already injected in a prior turn.
      const fresh = hits.filter((h) => !session.injectedSkills.has(h.name));
      if (fresh.length > 0) {
        for (const h of fresh) {
          logHit("skill", h.name, "skill-routing");
          session.injectedSkills.add(h.name);
        }
        promptText = formatSkillHint(fresh) + promptText;
      }
    } catch (err) {
      console.warn("[skill-router] failed:", err);
    }
  }

  // Intent classification: suggest /command if message looks like a command intent.
  if (!_skipEnrichment && isIntentClassifierReady()) {
    try {
      const hit = await classifyIntent(text);
      if (hit) {
        promptText =
          `[Intent hint — user message may be requesting: ${hit.usage} (score ${hit.score.toFixed(2)})]\n` +
          `If the user is asking you to perform this action, tell them to use ${hit.usage} directly.\n` +
          `[End intent hint]\n\n` + promptText;
      } else if (config.localLlmIntentFallback && session.activeProvider !== "local" && text.length > 25 && text.length <= 80) {
        // Embedding classifier skips long messages — try LLM for 25-80 char range
        const t0 = Date.now();
        const cmds = COMMAND_SPECS.map(c => ({ name: c.name, desc: c.desc }));
        const labels = await classifyIntentLLM(text, cmds);
        console.log(`[intent-llm] ${labels.length ? labels[0].intent : "none"} (${Date.now() - t0}ms)`);
        if (labels.length > 0) {
          const spec = COMMAND_SPECS.find(c => c.name === labels[0].intent);
          if (spec) {
            promptText =
              `[Intent hint — user message may be requesting: ${spec.usage} (LLM confidence ${labels[0].confidence.toFixed(2)})]\n` +
              `If the user is asking you to perform this action, tell them to use ${spec.usage} directly.\n` +
              `[End intent hint]\n\n` + promptText;
          }
        }
      }
    } catch (err) {
      console.warn("[intent-classifier] failed:", err);
    }
  }

  // Prepend specialist routing hint if pre-filter matched
  if (specialistHint) {
    promptText = specialistHint + promptText;
  }

  // 5d: User negation reflexion hint — when the user expresses
  // dissatisfaction ("不對", "重做", "wrong", etc.), prepend a
  // reflection hint so the agent self-corrects instead of repeating.
  const negationRe = /^(不對|不是|錯了|重做|重來|再試|wrong|redo|no that'?s wrong|try again|那不對|這不對)/i;
  if (negationRe.test(promptText.trim())) {
    promptText =
      `[Reflexion hint — user indicated your previous response was incorrect. ` +
      `Before answering, briefly reflect: what was wrong in your last response? ` +
      `What assumption should you revise? Then provide a corrected answer.]\n\n` +
      promptText;
  }

  const enrichmentMs = Date.now() - _enrichStart;
  if (enrichmentMs > 500) {
    console.log(`[enrichment] total pipeline: ${enrichmentMs}ms`);
  }

  await runPrompt(ctx, session, promptText);
});

// ─── Bot-to-bot relay incoming file → commands/relay.ts ────────────────────
setupRelayFileHandler(bot);
// File uploads: download into ACP_SESSION_CWD/uploads/, then hand Kiro
// a prompt that tells it where to find the file.
bot.on([
  "message:document",
  "message:photo",
  "message:voice",
  "message:audio",
  "message:video",
], async (ctx) => {
  if (!isAllowed(ctx)) {
    await ctx.reply("Not authorized.");
    return;
  }
  const chatId = ctx.chat.id;
  let session: ChatSession;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}`
    );
    return;
  }

  // Pick the best file object out of the various message kinds.
  const m = ctx.message;
  const photo = m.photo?.[m.photo.length - 1]; // largest
  const src =
    m.document ??
    photo ??
    m.voice ??
    m.audio ??
    m.video;
  if (!src) return;

  let origName =
    (m.document?.file_name as string | undefined) ??
    (m.audio?.file_name as string | undefined) ??
    (m.video?.file_name as string | undefined);
  if (!origName) {
    const ext =
      m.photo ? ".jpg" :
      m.voice ? ".ogg" :
      m.audio ? ".mp3" :
      m.video ? ".mp4" : "";
    origName = `${src.file_unique_id}${ext}`;
  }
  const safeName = sanitizeName(origName);
  const ts = new Date().toISOString().replace(/[:.]/g, "-").slice(0, 19);
  const relPath = path.join("uploads", `${chatId}-${ts}-${safeName}`);
  const absPath = path.join(config.sessionCwd, relPath);

  let notice: Awaited<ReturnType<typeof ctx.reply>> | null = null;
  try {
    notice = await ctx.reply(`Downloading ${safeName}…`);
    const file = await ctx.api.getFile(src.file_id);
    const url = `https://api.telegram.org/file/bot${config.telegramToken}/${file.file_path}`;
    await downloadToFile(url, absPath);
  } catch (err) {
    const msg = `Failed to download: ${(err as Error).message}`;
    if (notice) {
      try { await ctx.api.editMessageText(chatId, notice.message_id, msg); }
      catch { await ctx.reply(msg); }
    } else {
      await ctx.reply(msg);
    }
    return;
  }

  const caption = (m.caption ?? "").trim();

  const promptText =
    `User uploaded a file via Telegram.\n` +
    `Path (relative to cwd): ${relPath.replace(/\\/g, "/")}\n` +
    `Original name: ${origName}\n` +
    (caption ? `User caption: ${caption}\n` : "") +
    (DOC_CONVERTIBLE_EXTS.has(path.extname(absPath).toLowerCase())
      ? `Hint: This format can be converted to markdown with: py scripts/doc-to-md.py "${absPath}"\n`
      : "") +
    `Please inspect it and help accordingly.`;

  if (notice) {
    try {
      await ctx.api.editMessageText(
        chatId,
        notice.message_id,
        `Saved → ${relPath.replace(/\\/g, "/")}`
      );
    } catch { /* ignore */ }
  }

  session._lastUploadPath = absPath;
  await runPrompt(ctx, session, promptText);
});

bot.catch((err) => {
  console.error("Bot error:", err);
});

async function main() {
  console.log(`Starting Telegram ↔ Kiro bridge`);
  console.log(`  agent: ${config.agent.command} ${config.agent.args.join(" ")}`);
  console.log(`  cwd:   ${config.sessionCwd}`);
  console.log(`  PATH:  ${process.env.PATH ?? "(empty)"}`);
  console.log(`  Path:  ${process.env.Path ?? "(empty)"}`);
  console.log(`  PATH===Path: ${process.env.PATH === process.env.Path}`);
  console.log(
    `  auth:  ${
      config.allowedUserIds.length
        ? `restricted to ${config.allowedUserIds.join(", ")}`
        : "open to anyone"
    }`
  );
  // Ensure topics.json exists. Seeds built-in defaults on first run so
  // users can edit it without rebuilding.
  try {
    const { created, file } = bootstrapTopicsFile();
    console.log(
      `  topics: ${file}${created ? " (created from defaults)" : ""} — active source: ${topicRulesSource()}`
    );
  } catch (err) {
    console.warn("[topic-rules] bootstrap failed:", err);
  }
  // Initialize embedding-based NotebookLM router (non-blocking on failure).
  try {
    const routingPath = resolveBridgeConfigPath("notebooklm-routing.json", detectAgentConfigDir());
    const raw = await readFile(routingPath, "utf8");
    const routing = JSON.parse(raw);
    if (routing.version === 2) {
      await initEmbedRouter(routing);
    } else {
      console.log("[embed-router] skipped: routing.json is not v2");
    }
  } catch (err: any) {
    if (err?.code === "ENOENT") {
      console.log("[embed-router] skipped: notebooklm-routing.json not found");
    } else {
      console.warn("[embed-router] init failed:", err);
    }
  }
  // Initialize SQLite memory index (derived from facts .md).
  try {
    initMemoryDb();
    const uid = config.allowedUserIds[0] ?? 0;
    if (uid) {
      const { inserted, deleted } = syncFactsToDb(uid);
      console.log(`[memory-db] synced: +${inserted} -${deleted} facts`);
    }
  } catch (err) {
    console.warn("[memory-db] init failed:", err);
  }
  // Initialize memory recall (topic-based semantic retrieval).
  try {
    await initMemoryRecall();
  } catch (err) {
    console.warn("[memory-recall] init failed:", err);
  }
  // Initialize skill router (semantic skill matching).
  try {
    await initSkillRouter();
  } catch (err) {
    console.warn("[skill-router] init failed:", err);
  }
  // Initialize wiki retrieval (semantic wiki page matching).
  try {
    await initWikiRetrieval();
  } catch (err) {
    console.warn("[wiki-retrieval] init failed:", err);
  }
  // Initialize index retrieval (PageIndex tree-based document matching).
  try {
    const { initIndexRetrieval } = await import("./index-retrieval.js");
    await initIndexRetrieval();
  } catch (err) {
    console.warn("[index-retrieval] init failed:", err);
  }
  // Initialize intent classifier (natural language → /command matching).
  try {
    await initIntentClassifier(COMMAND_SPECS.map((s) => ({ name: s.name, usage: s.usage, desc: s.desc })));
  } catch (err) {
    console.warn("[intent-classifier] init failed:", err);
  }
  // Auto-regenerate specialist configs from specialist-domains.json.
  try {
    const { expandDomains, applyExpansions } = await import("./specialist-review.js");
    const expansions = await expandDomains();
    if (expansions.length > 0) {
      await applyExpansions(expansions);
      console.log(`[specialist] domain expansion: updated ${expansions.length} domain(s)`);
    }
    const { syncAllSpecialists } = await import("./specialist-create.js");
    const synced = await syncAllSpecialists();
    if (synced > 0) console.log(`[specialist] auto-synced ${synced} domain(s) from specialist-domains.json`);
  } catch (err) {
    console.warn("[specialist] auto-sync failed:", err);
  }
  // Load local specialist config (same-machine agent instances).
  try {
    await loadSpecialistsConfig(detectAgentConfigDir());
  } catch (err) {
    console.warn("[specialist] config load failed:", err);
  }
  // Auto-start llama.cpp server if configured (non-blocking on failure).
  try {
    const { autoStartLlamaCpp } = await import("./local-llm.js");
    await autoStartLlamaCpp();
  } catch (err) {
    console.warn("[local-llm] auto-start failed:", err);
  }
  // Start desktop pet WebSocket server (if PET_ENABLED=true).
  startPetServer();
  // Pet mini chat → inject into owner's live session
  onPetChat(async (text) => {
    const ownerId = config.allowedUserIds[0];
    if (!ownerId) return;
    try {
      const session = await sessions.get(ownerId, ownerId);
      // Build a minimal ctx that runPrompt can use to reply via Telegram
      const fakeCtx = {
        chat: { id: ownerId },
        from: { id: ownerId },
        message: undefined,
        api: bot.api,
        reply: (t: string, opts?: any) => bot.api.sendMessage(ownerId, t, opts),
      };
      await runPrompt(fakeCtx as any, session, `[from desktop pet] ${text}`);
    } catch (err) {
      console.error("[pet-chat] runPrompt failed:", err);
      petEmit({ type: "state", state: "error", text: "處理失敗" });
    }
  });
  await bot.start({
    allowed_updates: [...BOT_ALLOWED_UPDATES],
    onStart: async (me) => {
      console.log(`Bot online as @${me.username}`);
      // Start status monitoring server.
      startStatusServer(config.statusPort);
      // Publish the slash-command list so Telegram's Menu button (☰) shows it.
      registerBotCommands(bot).catch((err) =>
        console.error("[bot] registerBotCommands failed:", err),
      );
      // Doctor Pattern: startup health check → notify user.
      runHealthCheck().then((results) => {
        const report = formatReport(results);
        console.log("[doctor]", report.replace(/\n/g, " | "));
        const chatId = config.allowedUserIds[0];
        if (chatId) bot.api.sendMessage(chatId, report).catch(() => {});
      }).catch((err) => console.error("[doctor] health check crashed:", err));
      // Start bot-to-bot relay poller → commands/relay.ts
      initRelayPoller(bot);
      // Drain any pending fact-extractions that timed out in previous runs.
      // Fire-and-forget so bot startup isn't blocked on slow model calls.
      processPendingExtractions().catch((err) =>
        console.error("[memory] processPendingExtractions failed:", err),
      );
      // Reload scheduled prompts. Any entries whose runAt already passed
      // during bridge downtime are skipped (policy: skip, not replay) and
      // reported back to their originating chat.
      try {
        const { upcoming, missed } = await scheduleStore.load();

        // Seed default daily /dream schedule on first install
        const hasDream = scheduleStore.list().some(
          (e) => e.prompt === "/dream" && e.recurrence?.kind === "daily",
        );
        if (!hasDream && config.allowedUserIds.length > 0) {
          const primaryUser = config.allowedUserIds[0];
          const now = new Date();
          const runAt = new Date(now);
          runAt.setHours(4, 0, 0, 0);
          if (runAt.getTime() <= now.getTime()) runAt.setDate(runAt.getDate() + 1);
          await scheduleStore.add({
            chatId: primaryUser,
            userId: primaryUser,
            runAt: runAt.getTime(),
            prompt: "/dream",
            recurrence: { kind: "daily", hour: 4, minute: 0, second: 0 },
          });
          console.log(`[schedule] seeded default: daily 04:00 /dream for user ${primaryUser}`);
        }

        scheduler.armAll();
        console.log(
          `[schedule] loaded ${upcoming.length} upcoming, ${missed.length} missed`,
        );
        const missedByChat = new Map<number, ScheduleEntry[]>();
        for (const e of missed) {
          const arr = missedByChat.get(e.chatId) ?? [];
          arr.push(e);
          missedByChat.set(e.chatId, arr);
        }
        for (const [chatId, entries] of missedByChat) {
          const lines = entries.map((e) => {
            const preview = e.prompt.length > 60 ? e.prompt.slice(0, 60) + "…" : e.prompt;
            return `• ${e.id} — ${new Date(e.runAt).toLocaleString()}\n  ${preview}`;
          });
          await bot.api
            .sendMessage(
              chatId,
              `⚠️ bridge 重啟期間錯過 ${entries.length} 筆排程，依政策已略過：\n${lines.join("\n")}`,
            )
            .catch((err) =>
              console.error(`[schedule] missed-notify to ${chatId} failed:`, err),
            );
        }
      } catch (err) {
        console.error("[schedule] load failed:", err);
      }
      // If we were respawned by /restart, notify the requesting chat and
      // — if there's an active /goal on that chat with budget left — auto-
      // resume the continuation loop so the user doesn't have to send a
      // dummy message to wake it up. Policy:
      //   Q1 scope:  pending-only. We only auto-resume the chat that
      //              triggered /restart (marker.chatId). SIGINT / crash
      //              restarts won't auto-resume; user must poke manually.
      //   Q2 budget: keep turns_used as-is. The interrupted turn counts.
      //   Q3 trigger: auto-fire immediately after the "✅ Bridge
      //              restarted." message — shared UI with /goal resume +
      //              auto-scheduled continuations ("↻ Continuing (N/M)").
      try {
        const raw = await readFile(RESTART_PENDING_FILE, "utf8");
        const marker = JSON.parse(raw) as {
          chatId: number;
          userId?: number;
          savedFilename?: string;
          savedCount?: number;
          reason?: string;
        };
        await unlink(RESTART_PENDING_FILE).catch(() => {});
        if (typeof marker.chatId === "number") {
          let msg = "✅ Bridge restarted.";
          if (marker.savedFilename && marker.savedCount) {
            msg += `\nSaved ${marker.savedCount} messages → sessions/${marker.savedFilename}`;
          }
          if (marker.reason) {
            msg += `\nReason: ${marker.reason}`;
          }
          await bot.api.sendMessage(marker.chatId, msg);
          // Auto-resume goal continuation. Runs after the restart ack so
          // if this throws the user still sees the "✅" message.
          // restartReason (C3) is propagated into the continuation prompt
          // so the post-restart first turn knows why it was restarted.
          await maybeAutoResumeGoalAfterRestart(
            marker.chatId,
            marker.userId,
            marker.reason,
          ).catch((err) => {
            console.error(
              `[restart] goal auto-resume for chat ${marker.chatId} failed:`,
              err,
            );
          });
        }
      } catch (err: any) {
        if (err?.code !== "ENOENT") {
          console.error("[restart] post-restart notify failed:", err);
        }
      }
    },
  });
}

const shutdown = async (signal: string) => {
  console.log(`\nReceived ${signal}, shutting down…`);
  try {
    scheduler.stop();
  } catch {
    /* noop */
  }
  try {
    await bot.stop();
  } catch {
    /* noop */
  }
  try {
    await withTimeout(
      sessions.shutdown(),
      config.memoryExtractTimeoutMs + 30_000,
      "sessions.shutdown",
    );
  } catch (err) {
    console.error("[shutdown] graceful shutdown failed:", err);
  }
  try { stopPetApp(); } catch { /* noop */ }
  process.exit(0);
};

process.on("SIGINT", () => shutdown("SIGINT"));
process.on("SIGTERM", () => shutdown("SIGTERM"));

// Last-resort crash handlers: log and exit non-zero so the outer
// start.bat loop (or any supervisor) restarts us.
process.on("uncaughtException", (err) => {
  console.error("uncaughtException:", err);
  process.exit(1);
});
process.on("unhandledRejection", (reason) => {
  console.error("unhandledRejection:", reason);
  process.exit(1);
});

main().catch((err) => {
  console.error("Fatal:", err);
  process.exit(1);
});

