/**
 * Memory Recall — dynamically inject relevant topic shard facts into context
 * based on semantic similarity between the user message and topic representations.
 *
 * At init: builds a vector for each topic from "topic-name: keyword1, keyword2, ..."
 * Per turn: embeds user message, finds top matching topics above threshold,
 * reads those shards and returns facts to inject.
 */

import { embedText, cosineSim, isEmbedRouterReady } from "./embed-router.js";
import { readTopicFacts, listTopicShards } from "./facts-store.js";
import { getTopicRules } from "./topic-rules.js";
import { hybridSearch, getDb, type HybridHit } from "./memory-db.js";
import { rerankRecallHits } from "./local-llm.js";
import { config } from "./config.js";

// ─── Config ──────────────────────────────────────────────────────────────────

/** Minimum cosine similarity to consider a topic relevant. */
const RECALL_THRESHOLD = 0.65;
/** Max topics to recall per turn. */
const RECALL_TOP_K = 3;
/** Max total facts to inject (avoid blowing up context). */
const RECALL_MAX_FACTS = 30;
/** Skip messages shorter than this (too short for meaningful embedding). */
const MIN_MSG_LENGTH = 10;

// ─── State ───────────────────────────────────────────────────────────────────

let topicVectors: Map<string, Float32Array> = new Map(); // topic name → vector
let initialized = false;

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * Build topic vectors from current topics.json rules.
 * Call after initEmbedRouter() so the model is loaded.
 */
export async function initMemoryRecall(): Promise<void> {
  if (!isEmbedRouterReady()) return;
  const rules = getTopicRules();
  topicVectors.clear();
  for (const rule of rules) {
    if (rule.topic === "misc") continue; // skip catchall
    // Build repr: "topic-name: keyword1, keyword2, keyword3"
    const repr = `${rule.topic}: ${rule.keywords.join(", ")}`;
    const vec = await embedText(repr);
    if (vec) topicVectors.set(rule.topic, vec);
  }
  initialized = true;
  console.log(`[memory-recall] ready: ${topicVectors.size} topic vectors`);
}

export function isMemoryRecallReady(): boolean {
  return initialized && topicVectors.size > 0;
}

export interface RecallHit {
  topic: string;
  score: number;
  facts: string[]; // stripped fact text
}

/**
 * Given a user message, find semantically relevant topic shards and return
 * their facts. Returns empty array if nothing matches or module not ready.
 * `recentFacts` (optional) is the set of facts already in the preamble tail —
 * these are excluded from recall results to avoid duplication.
 * `excludeTopics` (optional) skips topics already covered by wiki retrieval.
 */
export async function recallRelevantFacts(
  userMsg: string,
  userId: number | string,
  recentFacts?: Set<string>,
  excludeTopics?: Set<string>,
  /** If provided, only consider these topics (scope filter for specialists). */
  includeTopics?: Set<string>,
  /** Override threshold (e.g. lower when scope already narrows candidates). */
  threshold = RECALL_THRESHOLD,
): Promise<RecallHit[]> {
  if (!initialized || topicVectors.size === 0) return [];
  if (userMsg.trim().length < MIN_MSG_LENGTH) return [];

  // ─── Hybrid path: use SQLite FTS5 + vector when DB is available ────────
  if (getDb()) {
    const hits = await hybridSearch(userMsg, {
      topK: RECALL_MAX_FACTS,
      threshold: 0.2, // lower threshold since decay reduces scores
      enableDecay: true,
      excludeTexts: recentFacts,
    });
    if (hits.length === 0) return [];

    // Rerank with local LLM if we have more candidates than needed
    let rankedHits = hits;
    if (config.localLlmRerank && hits.length > RECALL_MAX_FACTS / 2) {
      try {
        const t0 = Date.now();
        const reranked = await rerankRecallHits(
          userMsg,
          hits.map(h => ({ text: h.text, topic: h.topic || "misc", score: h.score })),
          RECALL_MAX_FACTS / 2,
        );
        console.log(`[memory-recall] rerank ${hits.length}→${reranked.length} (${Date.now() - t0}ms)`);
        if (reranked.length > 0) {
          rankedHits = reranked.map(r => ({
            text: r.text,
            topic: r.topic,
            score: r.rerankScore,
          })) as typeof hits;
        }
      } catch { /* rerank failed — use original order */ }
    }

    // Group by topic for output format compatibility
    const byTopic = new Map<string, { score: number; facts: string[] }>();
    for (const h of rankedHits) {
      const topic = h.topic || "misc";
      if (excludeTopics?.has(topic)) continue;
      if (includeTopics && !includeTopics.has(topic)) continue;
      const entry = byTopic.get(topic) ?? { score: 0, facts: [] };
      entry.score = Math.max(entry.score, h.score);
      entry.facts.push(h.text);
      byTopic.set(topic, entry);
    }

    const results: RecallHit[] = [];
    for (const [topic, { score, facts }] of byTopic) {
      results.push({ topic, score, facts });
    }
    results.sort((a, b) => b.score - a.score);
    return results.slice(0, RECALL_TOP_K);
  }

  // ─── Fallback: original topic-vector approach ──────────────────────────

  const queryVec = await embedText(userMsg);
  if (!queryVec) return [];

  // Score all topics
  const scored: Array<{ topic: string; score: number }> = [];
  for (const [topic, vec] of topicVectors) {
    if (excludeTopics?.has(topic)) continue;
    if (includeTopics && !includeTopics.has(topic)) continue;
    const score = cosineSim(queryVec, vec);
    if (score >= threshold) {
      scored.push({ topic, score });
    }
  }
  if (scored.length === 0) return [];
  scored.sort((a, b) => b.score - a.score);

  // Take top-K topics
  const topHits = scored.slice(0, RECALL_TOP_K);

  // Read shard facts for each hit, respecting total cap
  const results: RecallHit[] = [];
  let totalFacts = 0;
  for (const { topic, score } of topHits) {
    if (totalFacts >= RECALL_MAX_FACTS) break;
    const facts = readTopicFacts(userId, topic);
    if (facts.length === 0) continue;
    // Exclude facts already in the preamble tail
    const filtered = recentFacts
      ? facts.filter((f) => !recentFacts.has(f))
      : facts;
    if (filtered.length === 0) continue;
    const budget = RECALL_MAX_FACTS - totalFacts;
    const sliced = filtered.slice(-budget); // take most recent facts from shard
    totalFacts += sliced.length;
    results.push({ topic, score, facts: sliced });
  }

  return results;
}

/**
 * Format recall hits into a context block to prepend to the user message.
 */
export function formatRecallBlock(hits: RecallHit[]): string {
  if (hits.length === 0) return "";
  const sections = hits.map((h) => {
    const factLines = h.facts.map((f) => `- ${f}`).join("\n");
    return `[${h.topic}] (relevance ${h.score.toFixed(2)})\n${factLines}`;
  });
  return (
    `[Memory recall — dynamically retrieved facts relevant to this message]\n` +
    sections.join("\n\n") +
    `\n[End memory recall]\n\n`
  );
}

