/**
 * Skill Router — semantically match user messages to relevant skills.
 *
 * At init: reads SKILL.md frontmatter descriptions from SKILL_DIR, embeds each.
 * Per turn: embeds user message, finds top matching skill(s) above threshold,
 * returns a hint block so the agent knows which skill to prioritize.
 */

import { readFileSync, readdirSync, existsSync } from "node:fs";
import path from "node:path";
import { embedText, cosineSim, isEmbedRouterReady } from "./embed-router.js";
import { detectSkillDir } from "./memory.js";

// ─── Config ──────────────────────────────────────────────────────────────────

const SKILL_THRESHOLD = 0.65;
const SKILL_TOP_K = 2;
const MIN_MSG_LENGTH = 12;

// ─── State ───────────────────────────────────────────────────────────────────

interface SkillEntry {
  name: string;
  description: string;
  filePath: string;
  vector: Float32Array;
}

let skills: SkillEntry[] = [];
let initialized = false;

// ─── Public API ──────────────────────────────────────────────────────────────

export async function initSkillRouter(): Promise<void> {
  if (!isEmbedRouterReady()) return;
  const skillDir = detectSkillDir();
  if (!existsSync(skillDir)) return;

  skills = [];
  let entries: string[];
  try {
    entries = readdirSync(skillDir);
  } catch { return; }

  for (const name of entries) {
    const skillFile = path.join(skillDir, name, "SKILL.md");
    if (!existsSync(skillFile)) continue;
    const desc = extractDescription(skillFile);
    if (!desc) continue;
    const vec = await embedText(desc);
    if (!vec) continue;
    skills.push({ name, description: desc, filePath: skillFile, vector: vec });
  }
  initialized = true;
  console.log(`[skill-router] ready: ${skills.length} skill vectors`);
}

export function isSkillRouterReady(): boolean {
  return initialized && skills.length > 0;
}

export interface SkillHit {
  name: string;
  description: string;
  score: number;
}

export async function routeToSkills(userMsg: string): Promise<SkillHit[]> {
  if (!initialized || skills.length === 0) return [];
  if (userMsg.trim().length < MIN_MSG_LENGTH) return [];

  const queryVec = await embedText(userMsg);
  if (!queryVec) return [];

  const scored: SkillHit[] = [];
  for (const skill of skills) {
    const score = cosineSim(queryVec, skill.vector);
    if (score >= SKILL_THRESHOLD) {
      scored.push({ name: skill.name, description: skill.description, score });
    }
  }
  if (scored.length === 0) return [];
  scored.sort((a, b) => b.score - a.score);
  return scored.slice(0, SKILL_TOP_K);
}

export function formatSkillHint(hits: SkillHit[]): string {
  if (hits.length === 0) return "";
  const lines = hits.map(
    (h) => `- ${h.name} (score ${h.score.toFixed(2)}): ${h.description.slice(0, 100)}`
  );
  return (
    `[Skill routing — these skills are most relevant to this message, follow their instructions]\n` +
    lines.join("\n") +
    `\n[End skill routing]\n\n`
  );
}

// ─── Internals ───────────────────────────────────────────────────────────────

function extractDescription(filePath: string): string | null {
  try {
    const raw = readFileSync(filePath, "utf8");
    // Parse YAML frontmatter: between first --- and second ---
    const match = raw.match(/^---\s*\n([\s\S]*?)\n---/);
    if (!match) return null;
    const fm = match[1];
    // Extract description field
    const descMatch = fm.match(/^description:\s*(.+)$/m);
    if (!descMatch) return null;
    return descMatch[1].trim();
  } catch {
    return null;
  }
}

