  slug: string;
  summary: string;
  score: number;
  content: string;
}

export async function retrieveWikiPages(
  userMsg: string,
  /** If provided, only consider these wiki slugs (scope filter for specialists). */
  slugFilter?: Set<string>,
  /** Override threshold (e.g. lower when scope already narrows candidates). */
  threshold = WIKI_THRESHOLD,
): Promise<WikiHit[]> {
  if (!initialized || wikiEntries.length === 0) return [];
  if (userMsg.trim().length < MIN_MSG_LENGTH) return [];

  const queryVec = await embedText(userMsg);
  if (!queryVec) return [];

  const scored: Array<{ slug: string; summary: string; score: number }> = [];
  for (const entry of wikiEntries) {
    if (slugFilter && !slugFilter.has(entry.slug)) continue;
    const score = cosineSim(queryVec, entry.vector);
    if (score >= threshold) {
      scored.push({ slug: entry.slug, summary: entry.summary, score });
    }
  }
  if (scored.length === 0) return [];
  scored.sort((a, b) => b.score - a.score);

  const topHits = scored.slice(0, WIKI_TOP_K);
  const results: WikiHit[] = [];
  for (const { slug, summary, score } of topHits) {
    const content = readWikiPage(slug);
    if (content) {
      const injected = content.length > LONG_PAGE_THRESHOLD
        ? buildSectionIndex(slug, content)
        : content.slice(0, MAX_PAGE_CHARS);
      results.push({ slug, summary, score, content: injected });
    }
  }
  return results;
}

export function formatWikiBlock(hits: WikiHit[]): string {
  if (hits.length === 0) return "";
  const sections = hits.map(
    (h) => `## [[${h.slug}]] (relevance ${h.score.toFixed(2)})\n${h.content}`
  );
  return (
    `[Wiki retrieval — auto-loaded pages relevant to this message]\n` +
    sections.join("\n\n") +
    `\n[End wiki retrieval]\n\n`
  );
}

// ─── Internals ───────────────────────────────────────────────────────────────

/**
 * For long pages: extract H2 headings as a section index so the agent
 * knows what's available without consuming full context budget.
 */
function buildSectionIndex(slug: string, content: string): string {
  const headings: string[] = [];
  for (const line of content.split(/\r?\n/)) {
    const m = line.match(/^##\s+(.+)/);
    if (m) headings.push(m[1].trim());
  }
  if (headings.length === 0) return content.slice(0, MAX_PAGE_CHARS);
  return (
    `[長頁面 — 僅顯示段落目錄，需要細節請用 read tool 讀 \${MEMORY_DIR}/wiki/*/${slug}.md]\n` +
    headings.map((h) => `- ${h}`).join("\n")
  );
}

function parseWikiIndex(indexPath: string): Array<{ slug: string; summary: string }> {
  try {
    const raw = readFileSync(indexPath, "utf8");
    const results: Array<{ slug: string; summary: string }> = [];
    // Match lines like: - [[slug]] — summary text
    const re = /^\s*-\s*\[\[([^\]]+)\]\]\s*[—–-]\s*(.+)$/gm;
    let m: RegExpExecArray | null;
    while ((m = re.exec(raw)) !== null) {
      results.push({ slug: m[1].trim(), summary: m[2].trim() });
    }
    return results;
  } catch {
    return [];
  }
}

// ─── Auto-wikilink: zero-LLM entity linking ─────────────────────────────────

/**
 * Given wiki page content, find mentions of known wiki page titles/slugs
 * and wrap them in [[wikilinks]] if not already linked.
 * Zero LLM calls — pure regex matching against the wiki index.
 */
export function autoWikilink(content: string): string {
  if (!initialized || wikiEntries.length === 0) return content;

  // Build lookup: slug → possible mention patterns (slug itself + title words)
  const patterns: Array<{ slug: string; re: RegExp }> = [];
  for (const entry of wikiEntries) {
    // Skip very short slugs that would cause false positives
    if (entry.slug.length < 4) continue;
    // Match the slug as hyphenated or spaced form
    const slugWords = entry.slug.replace(/-/g, "[\\s-]");
    // Also try the summary's first meaningful phrase (before the colon/dash)
    const titleMatch = entry.summary.match(/^([^：:—–\-,，]{4,30})/);
    const titlePattern = titleMatch
      ? titleMatch[1].trim().replace(/[.*+?^${}()|[\]\\]/g, "\\$&")
      : null;

    // Build alternation: slug-as-words | title phrase
    const alts = [slugWords];
    if (titlePattern && titlePattern.length >= 4) alts.push(titlePattern);
    // Word-boundary match, case-insensitive, not inside existing [[...]]
    const re = new RegExp(`(?<!\\[\\[)\\b(${alts.join("|")})\\b(?!\\]\\])`, "gi");
    patterns.push({ slug: entry.slug, re });
  }

  let result = content;
  const linked = new Set<string>(); // only link each slug once

  for (const { slug, re } of patterns) {
    if (linked.has(slug)) continue;
    // Don't link a page to itself (check if this content IS that page)
    if (result.includes(`title:`) && result.includes(slug)) {
      const frontmatterMatch = result.match(/^---[\s\S]*?---/);
      if (frontmatterMatch && frontmatterMatch[0].includes(slug)) continue;
    }
    // Replace first occurrence only
    const match = re.exec(result);
    if (match) {
      // Don't replace inside frontmatter, code blocks, or existing links
      const before = result.slice(0, match.index);
      if (before.includes("```") && (before.match(/```/g)?.length ?? 0) % 2 === 1) continue;
      if (/^---[\s\S]*(?!---)$/.test(before)) continue;

      result = result.slice(0, match.index) +
        `[[${slug}]]` +
        result.slice(match.index + match[0].length);
      linked.add(slug);
      re.lastIndex = 0; // reset after mutation
    }
  }

  return result;
}

/**
 * Get all known wiki slugs (for external use).
 */
export function getWikiSlugs(): string[] {
  return wikiEntries.map(e => e.slug);
}

// ─── Page reading ────────────────────────────────────────────────────────────

function readWikiPage(slug: string): string | null {
  const wikiDir = path.join(config.memoryDir, "wiki");
  // Try each subdirectory: concepts, references, lessons, tasks, queries
  for (const sub of ["concepts", "references", "lessons", "tasks", "queries"]) {
    const filePath = path.join(wikiDir, sub, `${slug}.md`);
    if (existsSync(filePath)) {
      try {
        return readFileSync(filePath, "utf8");
      } catch {
        continue;
      }
    }
  }
  return null;
}

