/**
 * Intent Classifier — fuzzy match natural language messages to /commands.
 *
 * At init: embeds each command's description as a vector.
 * Per turn: if the user message looks like a command intent (not a question
 * to the agent), suggests the matching /command.
 */

import { embedText, cosineSim, isEmbedRouterReady } from "./embed-router.js";

// ─── Config ──────────────────────────────────────────────────────────────────

const INTENT_THRESHOLD = 0.65;
const MIN_MSG_LENGTH = 4;
/** Max message length — long messages are conversations, not commands. */
const MAX_MSG_LENGTH = 25;

// ─── Types ───────────────────────────────────────────────────────────────────

export interface IntentEntry {
  command: string;   // e.g. "backup"
  usage: string;     // e.g. "/backup"
  repr: string;      // description used for embedding
  vector: Float32Array;
}

export interface IntentHit {
  command: string;
  usage: string;
  score: number;
}

// ─── State ───────────────────────────────────────────────────────────────────

let intents: IntentEntry[] = [];
let initialized = false;

// ─── Public API ──────────────────────────────────────────────────────────────

/**
 * Initialize intent vectors from command specs.
 * Pass the same COMMAND_SPECS array used for help/menu.
 */
export async function initIntentClassifier(
  commands: Array<{ name: string; usage: string; desc: string }>
): Promise<void> {
  if (!isEmbedRouterReady()) return;
  intents = [];
  for (const cmd of commands) {
    // Skip meta commands that aren't useful to fuzzy-match
    if (["help", "menu", "hide", "start"].includes(cmd.name)) continue;
    const repr = `${cmd.name}: ${cmd.desc}`;
    const vec = await embedText(repr);
    if (vec) {
      intents.push({ command: cmd.name, usage: cmd.usage, repr, vector: vec });
    }
  }
  initialized = true;
  console.log(`[intent-classifier] ready: ${intents.length} command vectors`);
}

export function isIntentClassifierReady(): boolean {
  return initialized && intents.length > 0;
}

/**
 * Classify a user message as a potential command intent.
 * Returns the best match if above threshold, null otherwise.
 * Only fires for short messages that look like commands (not conversations).
 */
export async function classifyIntent(userMsg: string): Promise<IntentHit | null> {
  if (!initialized || intents.length === 0) return null;
  const trimmed = userMsg.trim();
  // Skip if too short, too long, or already a slash command
  if (trimmed.length < MIN_MSG_LENGTH) return null;
  if (trimmed.length > MAX_MSG_LENGTH) return null;
  if (trimmed.startsWith("/")) return null;

  const queryVec = await embedText(trimmed);
  if (!queryVec) return null;

  let best: IntentHit | null = null;
  for (const intent of intents) {
    const score = cosineSim(queryVec, intent.vector);
    if (score >= INTENT_THRESHOLD && (!best || score > best.score)) {
      best = { command: intent.command, usage: intent.usage, score };
    }
  }
  return best;
}

