/**
 * Index Retrieval — semantically match user messages to PageIndex tree indexes
 * and inject relevant chunks into the prompt (P3 #1).
 *
 * At init: reads all indexes, embeds each index's top-level tree.summary.
 * Per turn: embeds user message, cosine vs index summaries, on hit → queryIndex → inject chunks.
 */

import { embedText, cosineSim, isEmbedRouterReady } from "./embed-router.js";
import { listIndexes, queryIndex, type QueryResult } from "./page-index.js";
import { config } from "./config.js";

// ─── Config ──────────────────────────────────────────────────────────────────

const INDEX_THRESHOLD = 0.62;
const INDEX_TOP_K = 1;       // max indexes to inject per turn
const MAX_CHUNKS = 3;        // max chunks per index hit
const MIN_MSG_LENGTH = 15;

// ─── State ───────────────────────────────────────────────────────────────────

interface IndexEntry {
  slug: string;
  title: string;
  summary: string;
  vector: Float32Array;
}

let indexEntries: IndexEntry[] = [];
let initialized = false;

// ─── Public API ──────────────────────────────────────────────────────────────

export async function initIndexRetrieval(): Promise<void> {
  if (!isEmbedRouterReady()) return;

  const indexes = listIndexes(config.memoryDir);
  if (indexes.length === 0) return;

  indexEntries = [];
  for (const idx of indexes) {
    // Read the tree summary from the index file
    const summary = await getIndexSummary(idx.slug);
    if (!summary) continue;
    const repr = `${idx.title}: ${summary}`;
    const vec = await embedText(repr);
    if (vec) indexEntries.push({ slug: idx.slug, title: idx.title, summary, vector: vec });
  }

  if (indexEntries.length > 0) {
    initialized = true;
    console.log(`[index-retrieval] ready: ${indexEntries.length} index vectors`);
  }
}

export function isIndexRetrievalReady(): boolean {
  return initialized && indexEntries.length > 0;
}

export interface IndexHit {
  slug: string;
  title: string;
  score: number;
  result: QueryResult;
}

export async function retrieveIndexChunks(
  userMsg: string,
  threshold = INDEX_THRESHOLD,
): Promise<IndexHit[]> {
  if (!initialized || indexEntries.length === 0) return [];
  if (userMsg.trim().length < MIN_MSG_LENGTH) return [];

  const queryVec = await embedText(userMsg);
  if (!queryVec) return [];

  const scored: Array<{ slug: string; title: string; score: number }> = [];
  for (const entry of indexEntries) {
    const score = cosineSim(queryVec, entry.vector);
    if (score >= threshold) {
      scored.push({ slug: entry.slug, title: entry.title, score });
    }
  }
  if (scored.length === 0) return [];
  scored.sort((a, b) => b.score - a.score);

  const topHits = scored.slice(0, INDEX_TOP_K);
  const results: IndexHit[] = [];
  for (const { slug, title, score } of topHits) {
    try {
      const result = await queryIndex(config.memoryDir, slug, userMsg, MAX_CHUNKS);
      if (result.chunks.length > 0) {
        results.push({ slug, title, score, result });
      }
    } catch (err) {
      console.warn(`[index-retrieval] queryIndex failed for ${slug}:`, err);
    }
  }
  return results;
}

export function formatIndexBlock(hits: IndexHit[]): string {
  if (hits.length === 0) return "";
  const sections = hits.map((h) => {
    const branch = h.result.matched_branches[0] || "";
    const chunks = h.result.chunks.map((c) => c.text).join("\n\n");
    return (
      `## ${h.title} (index: ${h.slug}, relevance ${h.score.toFixed(2)})\n` +
      `Branch: ${branch}\n\n${chunks}`
    );
  });
  return (
    `[Index retrieval — auto-loaded chunks from document indexes]\n` +
    sections.join("\n\n") +
    `\n[End index retrieval]\n\n`
  );
}

// ─── Internals ───────────────────────────────────────────────────────────────

async function getIndexSummary(slug: string): Promise<string | null> {
  try {
    const { readFileSync } = await import("node:fs");
    const { join } = await import("node:path");
    const indexPath = join(config.memoryDir, "indexes", `${slug}.json`);
    const raw = JSON.parse(readFileSync(indexPath, "utf8"));
    return raw.tree?.summary || null;
  } catch {
    return null;
  }
}

