/**
 * Specialist — local agent instances (same machine, stdio AcpClient).
 *
 * Config lives at MEMORY_DIR/config/specialists.json (fallback: AGENT_CONFIG_DIR).
 * Each entry defines a named specialist with its own CLI harness, working
 * directory, and user-data-dir for skill isolation.
 *
 * Flow:
 *   1. Bridge intercepts RELAY_DELEGATE token
 *   2. If target matches a specialist name → dispatch here (not relay)
 *   3. Spawn or reuse an AcpClient for that specialist
 *   4. Inject goal prompt → collect result → return ResultPayload
 */
import { readFile } from "node:fs/promises";
import { appendFile, mkdir } from "node:fs/promises";
import path from "node:path";
import { AcpClient, type AcpClientOptions, type SessionUpdate } from "./acpClient.js";
import type { DelegatePayload, ResultPayload } from "./relay.js";
import { config, resolveBridgeConfigPath } from "./config.js";
import { buildSpecialistPreamble, getSpecialistScope } from "./specialist-create.js";
import { logEvent } from "./event-log.js";
import { runEnrichment } from "./enrichment.js";
import { isEmbedRouterReady } from "./embed-router.js";
import { isWikiRetrievalReady } from "./wiki-retrieval.js";
import { isMemoryRecallReady } from "./memory-recall.js";
import { registerTask, updateTask, completeTask } from "./status-store.js";
import { broadcastSSE } from "./status-server.js";
import { verifySpecialistOutput, buildRetryPrompt } from "./verifier.js";

// ─── Config types ──────────────────────────────────────────────────────────

export interface SpecialistHarness {
  command: string;
  args: string[];
}

export interface SpecialistEntry {
  /** Display/lookup name — must match the target in RELAY_DELEGATE token. */
  name: string;
  /** CLI command + args to spawn the agent. */
  harness: SpecialistHarness;
  /** Working directory for the specialist session. */
  cwd: string;
  /** Extra env vars merged into the specialist process. */
  env?: Record<string, string>;
  /** MCP servers to inject via ACP session/new. */
  mcpServers?: any[];
  /**
   * Model pin applied via ACP `session/set_config_option` after session/new.
   * Only the Claude adapter honours this (Kiro/Codex reject → best-effort
   * swallowed in AcpClient). Kiro/Codex pin model via harness args instead.
   */
  model?: string;
  /** Effort pin (Claude adapter only). Applied after model — see AcpClient. */
  effort?: string;
  /** Max turns before force-stopping a delegation. Default 15. */
  maxTurns?: number;
  /** Timeout (ms) for the entire delegation. Default 1800000 (30min). */
  timeoutMs?: number;
}

export type SpecialistsConfig = SpecialistEntry[];

// ─── Config loading ────────────────────────────────────────────────────────

let loadedConfig: SpecialistsConfig = [];
let configPath = "";
let loadedAgentConfigDir = "";

export function getSpecialists(): SpecialistsConfig {
  return loadedConfig;
}

/** Check if a target name matches a local specialist. */
export function isLocalSpecialist(target: string): boolean {
  return loadedConfig.some((s) => s.name === target);
}

/** Check if harness uses --agent flag (kiro-cli loads MCP servers from agent config). */
function harnessHasAgentFlag(entry: SpecialistEntry): boolean {
  return entry.harness.args.includes("--agent");
}

/**
 * Normalize stored MCP server configs into the ACP `session/new` schema.
 * The ACP SDK validates each server against zMcpServer: the stdio variant
 * requires `args` and `env` to be present, and `env` must be an ARRAY of
 * {name, value} — not the `{KEY: val}` object shape we store. HTTP/SSE
 * servers keep their `type` and get headers coerced to array form. Disabled
 * servers are dropped. Without this, session/new rejects with -32602.
 */
function toAcpMcpServers(servers: any[] | undefined): any[] | undefined {
  if (!Array.isArray(servers)) return undefined;
  const toArr = (env: any) =>
    Array.isArray(env)
      ? env
      : Object.entries(env ?? {}).map(([name, value]) => ({ name, value: String(value) }));
  return servers
    .filter((s) => s && !s.disabled)
    .map((s) => {
      if (s.type === "http" || s.type === "sse") {
        return {
          type: s.type,
          name: s.name,
          url: s.url,
          headers: Array.isArray(s.headers)
            ? s.headers
            : Object.entries(s.headers ?? {}).map(([name, value]) => ({ name, value: String(value) })),
        };
      }
      return {
        name: s.name,
        command: s.command,
        args: Array.isArray(s.args) ? s.args : [],
        env: toArr(s.env),
      };
    });
}

/** Expand ${MEMORY_DIR} / ${AGENT_CONFIG_DIR} / ${BRIDGE_DIR} in specialist config strings. */
function expandVars(entry: SpecialistEntry): SpecialistEntry {
  const vars: Record<string, string> = {
    MEMORY_DIR: config.memoryDir,
    AGENT_CONFIG_DIR: loadedAgentConfigDir,
    BRIDGE_DIR: path.resolve(config.sessionCwd),
  };
  const replace = (s: string) =>
    s.replace(/\$\{(\w+)\}/g, (_, k) => vars[k] ?? `\${${k}}`);
  return {
    ...entry,
    cwd: replace(entry.cwd),
    harness: { command: entry.harness.command, args: entry.harness.args.map(replace) },
    env: entry.env
      ? Object.fromEntries(Object.entries(entry.env).map(([k, v]) => [k, replace(v)]))
      : undefined,
  };
}

/** Load specialists.json from MEMORY_DIR/config (fallback: AGENT_CONFIG_DIR). Returns count loaded. */
export async function loadSpecialistsConfig(agentConfigDir: string): Promise<number> {
  loadedAgentConfigDir = agentConfigDir;
  configPath = resolveBridgeConfigPath("specialists.json", agentConfigDir);
  try {
    const raw = await readFile(configPath, "utf8");
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed)) {
      console.warn(`[specialist] ${configPath} is not an array, ignoring`);
      loadedConfig = [];
      return 0;
    }
    loadedConfig = (parsed as SpecialistsConfig).map(expandVars);
    console.log(`[specialist] loaded ${loadedConfig.length} specialist(s) from ${configPath}`);
    return loadedConfig.length;
  } catch (err: any) {
    if (err.code === "ENOENT") {
      console.log(`[specialist] no config at ${configPath} — feature disabled`);
    } else {
      console.warn(`[specialist] failed to load ${configPath}:`, err.message);
    }
    loadedConfig = [];
    return 0;
  }
}

// ─── Transcript persistence ────────────────────────────────────────────────

const transcriptDir = path.join(config.memoryDir, "sessions");

async function appendTranscript(name: string, role: "user" | "assistant", text: string): Promise<void> {
  const date = new Date().toISOString().slice(0, 10);
  const file = path.join(transcriptDir, `specialist-${name}-${date}.md`);
  await mkdir(transcriptDir, { recursive: true });
  const prefix = role === "user" ? "**User:**" : `**${name}:**`;
  const entry = `${prefix}\n${text}\n\n---\n\n`;
  await appendFile(file, entry, "utf8");
}

// ─── Instance management ───────────────────────────────────────────────────

interface LiveInstance {
  client: AcpClient;
  busy: boolean;
  sessionId: string;
}

const instances = new Map<string, LiveInstance>();

function getEntry(name: string): SpecialistEntry | undefined {
  return loadedConfig.find((s) => s.name === name);
}

/** Close and remove a specialist instance. */
export function closeInstance(name: string): void {
  const inst = instances.get(name);
  if (inst) {
    inst.client.close();
    instances.delete(name);
    console.log(`[specialist:${name}] closed (task done)`);
  }
}

/** Close a parallel instance by its unique instanceId. */
export function closeParallelInstance(instanceId: string): void {
  const inst = parallelInstances.get(instanceId);
  if (inst) {
    inst.client.close();
    parallelInstances.delete(instanceId);
    console.log(`[specialist:${instanceId}] parallel instance closed`);
  }
}

/** Parallel instances — keyed by unique instanceId, not reused. */
const parallelInstances = new Map<string, LiveInstance>();

/** Spawn a fresh instance (no reuse). Returns a unique instanceId. */
export async function spawnNew(name: string, userId?: number): Promise<{ instanceId: string; inst: LiveInstance }> {
  const entry = getEntry(name);
  if (!entry) throw new Error(`[specialist] unknown specialist: ${name}`);

  const instanceId = `${name}-${Math.random().toString(16).slice(2, 6)}`;

  const opts: AcpClientOptions = {
    command: entry.harness.command,
    args: [...entry.harness.args],
    cwd: path.resolve(entry.cwd),
    // TG_ACTIVE_USER_ID rides the same process-env path as MEMORY_DIR — the ACP
    // adapter forwards parent env to its MCP stdio children, so the memory server
    // resolves the active user id (else list_facts fails "active user id not configured").
    env: {
      MEMORY_DIR: config.memoryDir,
      ...(userId ? { TG_ACTIVE_USER_ID: String(userId) } : {}),
      ...entry.env,
    },
    acpModel: entry.model,
    acpEffort: entry.effort,
    promptRetries: 2,
    promptRetryBaseMs: 1000,
  };

  const client = new AcpClient(opts);
  client.on("stderr", (chunk) => {
    process.stderr.write(`[specialist:${instanceId}] ${chunk}`);
  });
  client.on("exit", (code) => {
    console.log(`[specialist:${instanceId}] process exited (code=${code})`);
    parallelInstances.delete(instanceId);
  });

  // If harness uses --agent flag, kiro-cli loads MCP servers from its own
  // agent config — passing them again in session/new causes a crash.
  const mcpServers = harnessHasAgentFlag(entry) ? undefined : toAcpMcpServers(entry.mcpServers);
  const sessionId = await client.initializeAndCreateSession(opts.cwd, mcpServers);
  const inst: LiveInstance = { client, busy: false, sessionId };
  parallelInstances.set(instanceId, inst);
  console.log(`[specialist:${instanceId}] spawned (parallel), session=${sessionId}`);
  logEvent("specialist_spawn", { instanceId, sessionId, parallel: true });
  return { instanceId, inst };
}

async function spawnOrReuse(name: string, userId?: number): Promise<LiveInstance> {
  const existing = instances.get(name);
  if (existing && !existing.client.isClosed) return existing;

  // Clean up stale entry
  if (existing) instances.delete(name);

  const entry = getEntry(name);
  if (!entry) throw new Error(`[specialist] unknown specialist: ${name}`);

  const opts: AcpClientOptions = {
    command: entry.harness.command,
    args: [...entry.harness.args],
    cwd: path.resolve(entry.cwd),
    // See spawnNew: TG_ACTIVE_USER_ID rides the same process-env path as MEMORY_DIR
    // so the memory MCP child can resolve the active user id.
    env: {
      MEMORY_DIR: config.memoryDir,
      ...(userId ? { TG_ACTIVE_USER_ID: String(userId) } : {}),
      ...entry.env,
    },
    acpModel: entry.model,
    acpEffort: entry.effort,
    promptRetries: 2,
    promptRetryBaseMs: 1000,
  };

  const client = new AcpClient(opts);
  client.on("stderr", (chunk) => {
    process.stderr.write(`[specialist:${name}] ${chunk}`);
  });
  client.on("exit", (code) => {
    console.log(`[specialist:${name}] process exited (code=${code})`);
    instances.delete(name);
  });

  const sessionId = await client.initializeAndCreateSession(opts.cwd,
    harnessHasAgentFlag(entry) ? undefined : toAcpMcpServers(entry.mcpServers));
  const inst: LiveInstance = { client, busy: false, sessionId };
  instances.set(name, inst);
  console.log(`[specialist:${name}] spawned, session=${sessionId}`);
  logEvent("specialist_spawn", { name, sessionId, parallel: false });
  return inst;
}

// ─── Dispatch ──────────────────────────────────────────────────────────────

export interface DispatchResult {
  payload: ResultPayload;
  /** Raw text chunks collected from the specialist's response. */
  rawOutput: string;
}

/**
 * Dispatch a delegation to a local specialist.
 * Spawns/reuses the specialist, sends the goal prompt, collects the response,
 * and returns a structured ResultPayload.
 */
export async function dispatchToSpecialist(
  target: string,
  delegate: DelegatePayload,
  userId?: number,
): Promise<DispatchResult> {
  const entry = getEntry(target);
  if (!entry) throw new Error(`[specialist] unknown: ${target}`);

  const inst = await spawnOrReuse(target, userId);
  if (inst.busy) {
    return {
      payload: { id: delegate.id, status: "failed", summary: "Specialist is busy with another task" },
      rawOutput: "",
    };
  }

  inst.busy = true;
  const maxTurns = delegate.maxTurns ?? entry.maxTurns ?? 15;
  const timeoutMs = entry.timeoutMs ?? 1_800_000;

  // Register with status store
  registerTask({
    taskId: delegate.id,
    type: "specialist",
    specialist: target,
    goal: delegate.goal.slice(0, 100),
  });

  // Build preamble from relevant topic shards
  const preamble = await buildSpecialistPreamble(target, userId ?? 0).catch(() => "");

  // Run scoped enrichment based on the delegation goal
  const scope = await getSpecialistScope(target).catch(() => undefined);
  const enrichment = await runEnrichment(delegate.goal, userId ?? 0, undefined, scope).catch(() => "");

  // Build the goal prompt
  const prompt = buildGoalPrompt(delegate, preamble, enrichment);

  let output = "";
  const updateHandler = (u: SessionUpdate) => {
    const up = u.update;
    if (
      (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk") 
    ) {
      const content = up.content as { type?: string; text?: string } | undefined;
      if (content?.type === "text" && typeof content.text === "string") {
        output += content.text;
        const role = up.sessionUpdate === "agent_thought_chunk" ? "thought" : "agent";
        broadcastSSE(delegate.id, { type: "chunk", role, text: content.text });
      }
    }
  };
  inst.client.on("update", updateHandler);

  try {
    // Multi-turn loop: keep prompting until agent says done or budget exhausted
    let turns = 0;
    let lastStopReason = "";

    const deadline = Date.now() + timeoutMs;

    while (turns < maxTurns && Date.now() < deadline) {
      turns++;
      updateTask(delegate.id, { turns, lastOutput: output.slice(-200) || undefined });
      broadcastSSE(delegate.id, { type: "status", status: "running", turns });
      const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";

      const result = await Promise.race([
        inst.client.prompt(promptText),
        new Promise<never>((_, reject) =>
          setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
        ),
      ]);

      lastStopReason = result.stopReason;
      // If agent stopped normally (end_turn), check if it needs more turns
      if (lastStopReason === "end_turn" || lastStopReason === "stop") break;
      // tool_use means agent is still working — loop for next turn
    }

    // Extract summary from output (last 2000 chars as summary)
    const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";

    const status: ResultPayload["status"] =
      Date.now() >= deadline ? "timeout" : "done";

    completeTask(delegate.id, status, { lastOutput: summary.slice(0, 200) });
    broadcastSSE(delegate.id, { type: "status", status });

    // Persist transcript for /memorytoskill
    appendTranscript(target, "user", prompt).catch(() => {});
    appendTranscript(target, "assistant", output).catch(() => {});

    logEvent("specialist_done", { target, taskId: delegate.id, status, turns });
    return {
      payload: { id: delegate.id, status, summary },
      rawOutput: output,
    };
  } catch (err: any) {
    const msg = err.message ?? String(err);
    const failStatus = msg.includes("timeout") ? "timeout" : "failed";
    completeTask(delegate.id, failStatus, { error: msg.slice(0, 200) });
    broadcastSSE(delegate.id, { type: "status", status: failStatus });
    logEvent("specialist_done", { target, taskId: delegate.id, status: failStatus, error: msg.slice(0, 100) });
    return {
      payload: { id: delegate.id, status: "failed", summary: `Error: ${msg.slice(0, 500)}` },
      rawOutput: output,
    };
  } finally {
    inst.client.removeListener("update", updateHandler);
    inst.busy = false;
    closeInstance(target);
  }
}

function buildGoalPrompt(d: DelegatePayload, preamble: string, enrichment?: string): string {
  let prompt = preamble;
  if (enrichment) prompt += enrichment;
  prompt += `[Delegation Task — id: ${d.id}]\n`;
  prompt += `Goal: ${d.goal}\n`;
  if (d.context) prompt += `Context: ${d.context}\n`;
  prompt += `\nComplete this task. When done, summarize what you accomplished.`;
  return prompt;
}

// ─── Parallel Dispatch ─────────────────────────────────────────────────────

export interface ParallelTask {
  taskId: string;
  target: string;
  payload: DelegatePayload;
}

export interface ParallelResult {
  taskId: string;
  target: string;
  status: "done" | "timeout" | "failed";
  summary: string;
  rawOutput: string;
}

/**
 * Dispatch multiple delegations in parallel. Each gets its own fresh instance.
 * Returns after all settle (Promise.allSettled).
 */
export async function dispatchParallel(
  tasks: ParallelTask[],
  userId?: number,
): Promise<ParallelResult[]> {
  const promises = tasks.map(async (task): Promise<ParallelResult> => {
    const entry = getEntry(task.target);
    if (!entry) {
      return { taskId: task.taskId, target: task.target, status: "failed", summary: `Unknown specialist: ${task.target}`, rawOutput: "" };
    }

    let instanceId = "";
    try {
      registerTask({
        taskId: task.taskId,
        type: "parallel_delegate",
        specialist: task.target,
        goal: task.payload.goal.slice(0, 100),
      });
      const spawned = await spawnNew(task.target, userId);
      instanceId = spawned.instanceId;
      const inst = spawned.inst;

      const maxTurns = task.payload.maxTurns ?? entry.maxTurns ?? 15;
      const timeoutMs = entry.timeoutMs ?? 1_800_000;

      const preamble = await buildSpecialistPreamble(task.target, userId ?? 0).catch(() => "");
      const scope = await getSpecialistScope(task.target).catch(() => undefined);
      const enrichment = await runEnrichment(task.payload.goal, userId ?? 0, undefined, scope).catch(() => "");
      const prompt = buildGoalPrompt(task.payload, preamble, enrichment);

      let output = "";
      const updateHandler = (u: SessionUpdate) => {
        const up = u.update;
        if (
          (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk")
        ) {
          const content = up.content as { type?: string; text?: string } | undefined;
          if (content?.type === "text" && typeof content.text === "string") {
            output += content.text;
            const role = up.sessionUpdate === "agent_thought_chunk" ? "thought" : "agent";
            broadcastSSE(task.taskId, { type: "chunk", role, text: content.text });
          }
        }
      };
      inst.client.on("update", updateHandler);

      try {
        let turns = 0;
        const deadline = Date.now() + timeoutMs;

        while (turns < maxTurns && Date.now() < deadline) {
          turns++;
          const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";
          const result = await Promise.race([
            inst.client.prompt(promptText),
            new Promise<never>((_, reject) =>
              setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
            ),
          ]);
          if (result.stopReason === "end_turn" || result.stopReason === "stop") break;
        }

        const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";
        const status: ParallelResult["status"] = Date.now() >= deadline ? "timeout" : "done";

        // Verifier gate (same as RELAY_DELEGATE path)
        if (status === "done" && output.length > 50) {
          const vr = await verifySpecialistOutput(task.payload.goal, output);
          logEvent("specialist_done", { taskId: task.taskId, target: task.target, verifier: vr.pass ? "PASS" : "NEEDS_FIX", source: vr.source, issues: vr.issues?.slice(0, 300) });
          if (!vr.pass && vr.issues) {
            console.log(`[parallel:${task.taskId}] verifier NEEDS_FIX (${vr.source}): ${vr.issues.slice(0, 100)}`);
            // Retry once
            try {
              const retryPrompt = buildRetryPrompt(task.payload.goal, vr.issues);
              output = "";
              const retryResult = await Promise.race([
                inst.client.prompt(retryPrompt),
                new Promise<never>((_, reject) => setTimeout(() => reject(new Error("timeout")), 120_000)),
              ]);
              void retryResult;
            } catch { /* retry failed — use original output */ }
          }
        }

        completeTask(task.taskId, status, { lastOutput: summary.slice(0, 200) });

        appendTranscript(task.target, "user", prompt).catch(() => {});
        appendTranscript(task.target, "assistant", output).catch(() => {});

        return { taskId: task.taskId, target: task.target, status, summary, rawOutput: output };
      } finally {
        inst.client.removeListener("update", updateHandler);
        closeParallelInstance(instanceId);
      }
    } catch (err: any) {
      if (instanceId) closeParallelInstance(instanceId);
      const msg = (err.message ?? String(err)).slice(0, 500);
      completeTask(task.taskId, "failed", { error: msg.slice(0, 200) });
      return { taskId: task.taskId, target: task.target, status: "failed", summary: `Error: ${msg}`, rawOutput: "" };
    }
  });

  const settled = await Promise.allSettled(promises);
  return settled.map((s, i) =>
    s.status === "fulfilled"
      ? s.value
      : { taskId: tasks[i].taskId, target: tasks[i].target, status: "failed" as const, summary: `Unexpected: ${s.reason}`, rawOutput: "" },
  );
}

// ─── Cleanup ───────────────────────────────────────────────────────────────

export async function shutdownAllSpecialists(): Promise<void> {
  for (const [name, inst] of instances) {
    console.log(`[specialist:${name}] shutting down...`);
    await inst.client.close();
  }
  instances.clear();
  proxyState.clear();
}

// ─── Transparent Proxy Mode ────────────────────────────────────────────────

const PROXY_DONE_RE = /<<PROXY_DONE>>/i;

interface ProxySession {
  specialistName: string;
  /** Conversation history for end-of-proxy summary. */
  history: { role: "user" | "assistant"; text: string }[];
  startedAt: number;
  lastActivity: number;
  /** Facts already injected via enrichment — dedup across turns. */
  injectedFacts: Set<string>;
  /** Total chars sent to specialist (preamble + enrichment + user text). */
  charsIn: number;
  /** Total chars received from specialist. */
  charsOut: number;
}

const proxyState = new Map<number, ProxySession>();

/** Check if a chatId is currently in proxy mode. */
export function isProxyActive(chatId: number): boolean {
  return proxyState.has(chatId);
}

/** Get the active proxy specialist name for a chatId. */
export function getProxyTarget(chatId: number): string | undefined {
  return proxyState.get(chatId)?.specialistName;
}

/** Get cumulative char stats for the active proxy session. */
export function getProxyStats(chatId: number): { charsIn: number; charsOut: number } | undefined {
  const ps = proxyState.get(chatId);
  return ps ? { charsIn: ps.charsIn, charsOut: ps.charsOut } : undefined;
}

/** Enter proxy mode: subsequent user messages go directly to this specialist. */
export function startProxy(chatId: number, specialistName: string): void {
  proxyState.set(chatId, {
    specialistName,
    history: [],
    startedAt: Date.now(),
    lastActivity: Date.now(),
    injectedFacts: new Set(),
    charsIn: 0,
    charsOut: 0,
  });
  console.log(`[specialist:proxy] chat ${chatId} → proxy to "${specialistName}"`);
}

/** Exit proxy mode. Returns the conversation history for summary injection. */
export function endProxy(chatId: number): ProxySession | undefined {
  const session = proxyState.get(chatId);
  proxyState.delete(chatId);
  if (session) {
    console.log(`[specialist:proxy] chat ${chatId} exited proxy (${session.history.length} exchanges)`);
    closeInstance(session.specialistName);
  }
  return session;
}

/** Register a callback for idle timeout auto-exit. */
/**
 * Send a user message to the proxied specialist and collect the response.
 * Returns the raw output text (caller is responsible for sending to Telegram
 * and extracting memory tokens).
 */
export async function promptProxy(
  chatId: number,
  text: string,
  onChunk?: (currentOutput: string) => void,
  userId?: number,
): Promise<{ output: string; stopReason: string; proxyDone: boolean }> {
  const ps = proxyState.get(chatId);
  if (!ps) throw new Error("[specialist:proxy] no active proxy for this chat");

  const inst = await spawnOrReuse(ps.specialistName, userId);

  // First prompt: prepend preamble + instruction so specialist knows about PROXY_DONE
  const isFirst = ps.history.length === 0;
  let prompt: string;
  if (isFirst) {
    const preamble = await buildSpecialistPreamble(ps.specialistName, userId ?? 0, { proxy: true }).catch(() => "");
    // Run scoped enrichment for the first message too
    const scope = await getSpecialistScope(ps.specialistName).catch(() => undefined);
    console.log(`[specialist:proxy] enrichment scope for ${ps.specialistName}:`, JSON.stringify(scope ?? null));
    console.log(`[specialist:proxy] subsystem ready: embed=${isEmbedRouterReady()}, wiki=${isWikiRetrievalReady()}, recall=${isMemoryRecallReady()}`);
    const enrichment = await runEnrichment(text, userId ?? 0, ps.injectedFacts, scope).catch((e) => { console.warn("[specialist:proxy] enrichment error:", e); return ""; });
    console.log(`[specialist:proxy] enrichment result length: ${enrichment.length}${enrichment.length > 0 ? " (has content)" : " (empty)"}`);
    prompt = `${preamble}[System] You are in a proxy conversation with the user. Do NOT append <<PROXY_DONE>> unless the user explicitly ends the conversation (says goodbye, "沒了", "就這樣", "thanks that's all", etc.). Simply answering a question does NOT mean the conversation is over — always assume follow-ups.\n\n${enrichment}User: ${text}`;
  } else {
    // Subsequent turns: still run scoped enrichment (dynamic per-turn)
    const scope = await getSpecialistScope(ps.specialistName).catch(() => undefined);
    console.log(`[specialist:proxy] turn enrichment scope:`, JSON.stringify(scope ?? null));
    const enrichment = await runEnrichment(text, userId ?? 0, ps.injectedFacts, scope).catch((e) => { console.warn("[specialist:proxy] turn enrichment error:", e); return ""; });
    console.log(`[specialist:proxy] turn enrichment length: ${enrichment.length}`);
    prompt = enrichment ? `${enrichment}${text}` : text;
  }

  let output = "";
  const updateHandler = (u: SessionUpdate) => {
    const up = u.update;
    if (
      (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk")
    ) {
      const content = up.content as { type?: string; text?: string } | undefined;
      if (content?.type === "text" && typeof content.text === "string") {
        output += content.text;
        onChunk?.(output);
      }
    }
  };
  inst.client.on("update", updateHandler);

  try {
    const result = await inst.client.prompt(prompt);
    ps.charsIn += prompt.length;
    ps.charsOut += output.length;
    ps.history.push({ role: "user", text });
    ps.history.push({ role: "assistant", text: output });
    ps.lastActivity = Date.now();
    // Persist transcript for /memorytoskill
    appendTranscript(ps.specialistName, "user", text).catch(() => {});
    appendTranscript(ps.specialistName, "assistant", output).catch(() => {});
    // Detect <<PROXY_DONE>> — specialist signals it's finished
    const proxyDone = PROXY_DONE_RE.test(output);
    const cleanOutput = output.replace(PROXY_DONE_RE, "").trim();
    return { output: cleanOutput, stopReason: result.stopReason, proxyDone };
  } finally {
    inst.client.removeListener("update", updateHandler);
  }
}

/** Build a summary of the proxy conversation for injection into main agent. */
export function buildProxySummary(session: ProxySession): string {
  const lines: string[] = [];
  const count = Math.floor(session.history.length / 2);
  // Keep last 5 exchanges max for summary
  const recent = session.history.slice(-10);
  for (const h of recent) {
    const prefix = h.role === "user" ? "User" : session.specialistName;
    const truncated = h.text.length > 300 ? h.text.slice(0, 300) + "…" : h.text;
    lines.push(`${prefix}: ${truncated}`);
  }
  return (
    `[系統] Specialist "${session.specialistName}" proxy 結束（共 ${count} 輪對話）\n` +
    `以下是最近的對話摘要：\n` +
    lines.join("\n") + "\n" +
    `[End proxy summary]\n\n` +
    `使用者已切回跟你對話。如果 specialist 的工作有後續，請接續處理。`
  );
}

